import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, GroundingChunk, AttachedFile } from './types';
import { streamGeminiResponse } from './services/api';
import { MessageBubble } from './components/MessageBubble';
import { ChatInput, ChatInputHandle } from './components/ChatInput';
import { Sparkles, BrainCircuit, MessageSquarePlus } from 'lucide-react';

const SIMPLE_PROMPTS = [
  "Explain quantum computing principles simply.",
  "Analyze the attached code for security vulnerabilities.",
  "Summarize the key takeaways from a YouTube video.",
  "Draft a professional email responding to a client."
];

const App: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [alertMessage, setAlertMessage] = useState<string>('');
  const [statusMessage, setStatusMessage] = useState<string>('');
  const [selectedPrompt, setSelectedPrompt] = useState<string>('');
  const [activeFile, setActiveFile] = useState<AttachedFile | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatInputRef = useRef<ChatInputHandle>(null);

  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      // Alt + / : Focus Input
      if (e.altKey && e.key === '/') {
        e.preventDefault();
        chatInputRef.current?.focus();
      }
      // Alt + N : New Chat
      if (e.altKey && e.key.toLowerCase() === 'n') {
        e.preventDefault();
        handleNewChat();
      }
    };
    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [messages.length]); 

  const showAlert = (msg: string) => {
    setAlertMessage(msg);
    setTimeout(() => setAlertMessage(''), 3000);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleNewChat = () => {
    if (messages.length > 0) {
      if (window.confirm("Start new chat? Current history will be cleared.")) {
        setMessages([]);
        setActiveFile(null);
        showAlert("Started a new chat");
        chatInputRef.current?.focus();
      }
    } else {
       chatInputRef.current?.focus();
    }
  };

  const handleSendMessage = async (content: string, file: File | null, youtubeLinks: string[], isUrlUnderstanding: boolean) => {
    setIsLoading(true);
    setStatusMessage("AI is thinking...");

    // File uploaded only for this request if provided
    const requestFile = file ? {
      file: file,
      mimeType: file.type || 'application/octet-stream',
      name: file.name
    } : null;

    const newUserMessage: ChatMessage = { role: 'user', content, isComplete: true };
    const updatedMessages = [...messages, newUserMessage];

    setMessages(prev => [...prev, newUserMessage]);
    setMessages(prev => [...prev, { role: 'assistant', content: '', isComplete: false }]);

    await streamGeminiResponse(
      updatedMessages,
      requestFile,
      youtubeLinks,
      isUrlUnderstanding,
      (content, groundingChunks) => {
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
            lastMsg.content = content;
            if (groundingChunks) lastMsg.groundingChunks = groundingChunks;
          }
          return newHistory;
        });
      },
      () => {
        setIsLoading(false);
        setStatusMessage("Ready");
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
            lastMsg.isComplete = true;
          }
          return newHistory;
        });
      },
      (error) => {
        setIsLoading(false);
        setStatusMessage("Error");
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
              lastMsg.content += `\n\n**Error:** ${error.message}`;
              lastMsg.isComplete = true; 
          }
          return newHistory;
        });
      }
    );
  };

  return (
    <div className="flex flex-col h-screen bg-background text-gray-100 font-sans selection:bg-primary/30">
      {alertMessage && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 bg-gray-900/90 text-white px-6 py-2 rounded-full text-sm font-medium backdrop-blur-sm border border-gray-700 animate-in fade-in slide-in-from-top-2 z-50 shadow-xl">
          {alertMessage}
        </div>
      )}

      <header className="flex-shrink-0 h-16 border-b border-gray-700/50 bg-surface/50 backdrop-blur-md sticky top-0 z-10 flex items-center px-4 md:px-8 justify-between">
        <h1 className="font-bold text-lg tracking-tight text-white flex items-center gap-2">
          <Sparkles size={18} className="text-primary" />
          AI assistant
        </h1>
        <button 
          onClick={handleNewChat} 
          title="New Chat (Alt+N)"
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-primary hover:bg-blue-600 shadow-lg shadow-blue-500/20 text-xs font-bold text-white transition-all active:scale-95 border border-transparent"
        >
          <MessageSquarePlus size={16} />
          <span>Start New Chat</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto px-4 py-6 md:px-8 scroll-smooth">
        <div className="max-w-4xl mx-auto min-h-full flex flex-col">
          {messages.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center animate-in fade-in slide-in-from-bottom-4 duration-700 pb-10">
              <div className="w-16 h-16 rounded-2xl bg-surface border border-gray-700 flex items-center justify-center mb-6 shadow-xl">
                <BrainCircuit size={32} className="text-gray-400" />
              </div>
              <h2 className="text-2xl font-bold text-gray-200 mb-2">How can I help you?</h2>
              <p className="text-gray-400 mb-8 text-center max-w-md text-sm">
                I can summarize YouTube videos, analyze files, and browse the web with URL Understanding.
              </p>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 w-full max-w-2xl">
                {SIMPLE_PROMPTS.map((prompt, i) => (
                  <button key={i} onClick={() => setSelectedPrompt(prompt)} className="group flex items-center text-left p-4 rounded-xl bg-surface/30 border border-gray-700/50 hover:bg-surface hover:border-primary/40 transition-all duration-200">
                    <span className="text-sm font-medium text-gray-300 group-hover:text-white">{prompt}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="flex flex-col gap-2">
              {messages.map((msg, idx) => <MessageBubble key={idx} message={msg} />)}
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
      </main>

      <div className="flex-shrink-0 bg-surface border-t border-gray-700/50">
        <ChatInput 
          ref={chatInputRef}
          onSendMessage={handleSendMessage} 
          isLoading={isLoading} 
          prefilledText={selectedPrompt}
          onClearPrefill={() => setSelectedPrompt('')}
          statusMessage={statusMessage}
        />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useImperativeHandle, forwardRef } from 'react';
import { Send, Loader2, Paperclip, X, Youtube, Globe, Mic, Square, Plus, FileUp, ChevronUp } from 'lucide-react';
import { YouTubeModal } from './YouTubeModal';
import { transcribeAudio } from '../services/api';

interface ChatInputProps {
  onSendMessage: (content: string, file: File | null, youtubeLinks: string[], isUrlUnderstanding: boolean) => void;
  isLoading: boolean;
  prefilledText?: string;
  onClearPrefill?: () => void;
  statusMessage?: string;
}

export interface ChatInputHandle {
  focus: () => void;
}

export const ChatInput = forwardRef<ChatInputHandle, ChatInputProps>(({ 
  onSendMessage, 
  isLoading, 
  prefilledText, 
  onClearPrefill,
  statusMessage
}, ref) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [ytLinks, setYtLinks] = useState<string[]>([]);
  const [isUrlUnderstanding, setIsUrlUnderstanding] = useState(false);
  const [isYtModalOpen, setIsYtModalOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Voice Input State
  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const firstMenuItemRef = useRef<HTMLButtonElement>(null);

  useImperativeHandle(ref, () => ({
    focus: () => {
      textareaRef.current?.focus();
    }
  }));

  useEffect(() => {
    if (prefilledText) {
      setInput(prefilledText);
      textareaRef.current?.focus();
      if (onClearPrefill) onClearPrefill();
    }
  }, [prefilledText, onClearPrefill]);

  useEffect(() => {
    // Focus first menu item when menu opens
    if (isMenuOpen) {
        // Small timeout to allow render
        setTimeout(() => firstMenuItemRef.current?.focus(), 50);
    }
  }, [isMenuOpen]);

  // Click outside to close menu
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    if (isMenuOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [isMenuOpen]);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() && !selectedFile && ytLinks.length === 0) return;

    onSendMessage(input, selectedFile, ytLinks, isUrlUnderstanding);
    setInput('');
    setSelectedFile(null); 
    setYtLinks([]);
    if (fileInputRef.current) fileInputRef.current.value = '';

    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const file = new File([blob], "voice_input.webm", { type: 'audio/webm' });

        // Cleanup stream tracks
        stream.getTracks().forEach(track => track.stop());

        setIsRecording(false);
        setIsTranscribing(true);

        try {
          const text = await transcribeAudio(file);
          if (text && text.trim()) {
            onSendMessage(text.trim(), null, [], isUrlUnderstanding);
          }
        } catch (err) {
          console.error("Transcription error:", err);
          alert("Failed to transcribe audio.");
        } finally {
          setIsTranscribing(false);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access denied or not available.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
  };

  const toggleVoice = () => {
    if (isLoading || isTranscribing) return;
    if (isRecording) stopRecording();
    else startRecording();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Alt + S : Send
    if (e.altKey && e.key.toLowerCase() === 's') {
      e.preventDefault();
      handleSubmit();
      return;
    }
    // Alt + A : Open Add Menu
    if (e.altKey && e.key.toLowerCase() === 'a') {
      e.preventDefault();
      setIsMenuOpen(prev => !prev);
      return;
    }
    // Alt + V : Voice
    if (e.altKey && e.key.toLowerCase() === 'v') {
      e.preventDefault();
      toggleVoice();
      return;
    }
    // Enter to send (without Shift)
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
      setIsMenuOpen(false);
      textareaRef.current?.focus();
    }
  };

  const handleMenuKeyDown = (e: React.KeyboardEvent) => {
     if (e.key === 'Escape') {
         setIsMenuOpen(false);
         textareaRef.current?.focus();
     }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [input]);

  const isSendDisabled = (!input.trim() && !selectedFile && ytLinks.length === 0) || isLoading || isRecording || isTranscribing;

  return (
    <div className="w-full bg-surface border-t border-gray-700/50 px-4 pt-4 pb-6">
      <div role="alert" aria-live="polite" className="sr-only">
        {statusMessage}
        {isRecording && "Recording voice input"}
        {isTranscribing && "Transcribing audio"}
      </div>

      <div className="max-w-3xl mx-auto relative flex flex-col gap-3">
        {/* Attachment Display */}
        {(selectedFile || ytLinks.length > 0) && (
        <div className="flex flex-wrap gap-2 mb-1">
          {selectedFile && (
             <div className="flex items-center gap-2 bg-background border border-gray-700 rounded-lg px-3 py-2 animate-in slide-in-from-bottom-2">
               <div className="flex flex-col">
                  <p className="text-[10px] text-primary font-bold uppercase tracking-wider">File</p>
                  <p className="text-sm text-gray-200 truncate max-w-[150px]">{selectedFile.name}</p>
               </div>
               <button 
                 onClick={() => { setSelectedFile(null); if (fileInputRef.current) fileInputRef.current.value = ''; }} 
                 className="ml-2 flex items-center gap-1 p-1 hover:bg-gray-700 rounded-lg text-gray-400 hover:text-white transition-colors border border-transparent hover:border-gray-600"
                 title="Remove"
               >
                 <X size={14} />
               </button>
             </div>
          )}

          {ytLinks.map((link, idx) => (
            <div key={idx} className="flex items-center gap-2 bg-background border border-gray-700 rounded-lg px-3 py-2 animate-in slide-in-from-bottom-2">
               <div className="flex flex-col">
                  <p className="text-[10px] text-red-500 font-bold uppercase tracking-wider">YouTube</p>
                  <p className="text-sm text-gray-200 truncate max-w-[200px]">{link}</p>
               </div>
               <button 
                 onClick={() => setYtLinks(prev => prev.filter((_, i) => i !== idx))} 
                 className="ml-2 flex items-center gap-1 p-1 hover:bg-gray-700 rounded-lg text-gray-400 hover:text-white transition-colors border border-transparent hover:border-gray-600"
                 title="Remove"
               >
                 <X size={14} />
               </button>
             </div>
          ))}
        </div>
        )}

        <form onSubmit={handleSubmit} className="relative flex flex-col gap-3">
          {/* Input Area */}
          <div className="relative bg-background rounded-xl border border-gray-700/50 focus-within:border-primary/50 focus-within:ring-1 focus-within:ring-primary/20 transition-all shadow-lg p-2">
             <textarea
                ref={textareaRef}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={isRecording ? "Listening..." : "Ask anything..."}
                disabled={isRecording || isTranscribing}
                className={`w-full bg-transparent text-gray-100 placeholder-gray-500 resize-none outline-none p-2 min-h-[50px] max-h-[200px] text-sm md:text-base scrollbar-hide ${isRecording ? 'animate-pulse text-red-400' : ''}`}
                rows={1}
            />
          </div>

          <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*,video/*,audio/*,.pdf,.txt,.md,.js,.ts,.py,.java,.c,.cpp,.html,.css,.json,.csv" />

          {/* Toolbar */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
               {/* Voice Button */}
               <button
                 type="button"
                 onClick={toggleVoice}
                 disabled={isLoading || isTranscribing}
                 className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all ${isRecording ? 'bg-red-500/10 text-red-500 border border-red-500/50' : 'bg-surface hover:bg-gray-800 text-gray-400 hover:text-white border border-transparent'}`}
                 title="Toggle Voice (Alt+V)"
               >
                 {isTranscribing ? <Loader2 size={18} className="animate-spin" /> : isRecording ? <Square size={18} fill="currentColor" /> : <Mic size={18} />}
                 <span className="hidden sm:inline">{isRecording ? 'Stop' : 'Voice'}</span>
               </button>

               {/* Add Menu */}
               <div className="relative" ref={menuRef}>
                  <button
                    type="button"
                    onClick={() => setIsMenuOpen(!isMenuOpen)}
                    disabled={isRecording}
                    className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all ${isMenuOpen ? 'bg-gray-800 text-white' : 'bg-surface hover:bg-gray-800 text-gray-400 hover:text-white'} border border-transparent`}
                    title="Add content (Alt+A)"
                    aria-haspopup="true"
                    aria-expanded={isMenuOpen}
                  >
                    <Plus size={18} />
                    <span>Add</span>
                  </button>

                  {isMenuOpen && (
                    <div 
                        role="menu" 
                        className="absolute bottom-full left-0 mb-2 w-48 bg-gray-800 rounded-xl border border-gray-700 shadow-xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 z-50 flex flex-col p-1"
                        onKeyDown={handleMenuKeyDown}
                    >
                        <button 
                            ref={firstMenuItemRef}
                            role="menuitem"
                            type="button"
                            onClick={() => { fileInputRef.current?.click(); setIsMenuOpen(false); }}
                            className="flex items-center gap-3 w-full px-3 py-2.5 text-left text-sm text-gray-200 hover:bg-gray-700 rounded-lg transition-colors focus:outline-none focus:bg-gray-700"
                        >
                            <FileUp size={16} className="text-blue-400" />
                            <span>Upload Files</span>
                        </button>
                        <button 
                            role="menuitem"
                            type="button"
                            onClick={() => { setIsYtModalOpen(true); setIsMenuOpen(false); }}
                            className="flex items-center gap-3 w-full px-3 py-2.5 text-left text-sm text-gray-200 hover:bg-gray-700 rounded-lg transition-colors focus:outline-none focus:bg-gray-700"
                        >
                            <Youtube size={16} className="text-red-500" />
                            <span>YouTube Link</span>
                        </button>
                    </div>
                  )}
               </div>

               {/* URL Understanding */}
               <button
                 type="button"
                 onClick={() => setIsUrlUnderstanding(!isUrlUnderstanding)}
                 disabled={isRecording}
                 className={`p-2 rounded-lg transition-all border ${isUrlUnderstanding ? 'bg-blue-500/10 text-blue-400 border-blue-500/30' : 'bg-surface hover:bg-gray-800 text-gray-400 hover:text-white border-transparent'}`}
                 title={isUrlUnderstanding ? "Disable URL Understanding" : "Enable URL Understanding"}
               >
                 <Globe size={18} />
               </button>
            </div>

            <button
                type="submit"
                onClick={() => handleSubmit()}
                disabled={isSendDisabled}
                title="Send (Alt+S)"
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold text-sm transition-all ${isSendDisabled ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-500/20 active:scale-95'}`}
            >
                {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
                <span className="hidden sm:inline">Send</span>
            </button>
          </div>
        </form>
      </div>

      <YouTubeModal 
        isOpen={isYtModalOpen} 
        onClose={() => { setIsYtModalOpen(false); textareaRef.current?.focus(); }} 
        onAdd={(url) => setYtLinks(prev => [...prev, url])} 
      />
    </div>
  );
});

ChatInput.displayName = 'ChatInput';

