import React, {
  useState,
  useRef,
  useEffect,
  KeyboardEvent,
  useCallback,
} from 'react';
import { useChatContext } from './ChatContext';
import { sendPrompt } from './api';
import { ChatInputProps } from './types'; // Assuming this is defined
import './ChatInput.css';

const ChatInput: React.FC<ChatInputProps> = ({ onEdit }) => {
  const { onSendMessage, selectedPrompt, setSelectedPrompt } = useChatContext();
  const [inputText, setInputText] = useState<string>('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const menuItemsRef = useRef<Array<HTMLButtonElement | null>>([]);
  const [isUrlUnderstandingOn, setIsUrlUnderstandingOn] = useState(false); // New state

  const handleInputChange = (event: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInputText(event.target.value);
  };

  const handleSendMessage = async () => {
    if (inputText.trim() === '') {
      return;
    }
    await onSendMessage(inputText.trim());
    setInputText('');
  };

  const handleKeyDown = (event: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      handleSendMessage();
    }
  };

  const handleEdit = (content: string) => {
    setInputText(content);
    // Optionally focus the textarea
    textareaRef.current?.focus();
  };

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  const handleMenuKeyDown = (e: KeyboardEvent) => {
    if (!menuItemsRef.current) return;
